mapper.select:
SELECT rd.approveId, bd.buyContractId, rd.sellContractId, rd.receiveApproveDate, bd.receiveBillApproveDate, cd.confirmReceiptApproveDate FROM (SELECT t.approve_id AS approveId, r.contract_id AS sellContractId, MAX(a.last_approve_date) AS receiveApproveDate FROM t_apply_receive r INNER JOIN t_pm_approve a ON r.approve_id = a.id AND a.`status` = 'D' INNER JOIN t_ctr_contract t ON t.id = r.contract_id WHERE r.contract_id IN
#{sellContractId}
AND r.contract_no = t.contract_no GROUP BY r.contract_id) rd LEFT JOIN (SELECT t.approve_id AS approveId, n.contract_id AS buyContractId, MAX(a.last_approve_date) AS receiveBillApproveDate FROM t_apply_invoice_received n INNER JOIN t_pm_approve a ON n.approve_id = a.id AND a.`status` = 'D' INNER JOIN t_ctr_contract t ON t.id = n.contract_id WHERE n.contract_id IN
#{buyContractId}
AND n.contract_no = t.contract_no GROUP BY n.contract_id) bd ON rd.approveId = bd.approveId LEFT JOIN (SELECT t.approve_id AS approveId, MAX(a.last_approve_date) AS confirmReceiptApproveDate FROM t_apply_confirm_receipt c INNER JOIN t_pm_approve a ON c.approve_id = a.id AND a.`status` = 'D' INNER JOIN t_ctr_contract t ON t.id = c.contract_id WHERE c.contract_id IN
#{sellContractId}
AND c.contract_no = t.contract_no GROUP BY c.contract_id) cd ON cd.approveId = bd.approveId
